import { createContext, useContext, useEffect, useState, ReactNode } from "react";

interface AuthContextType {
  isLoggedIn: boolean;
  adminEmail: string;
  login: (email: string, password: string) => boolean;
  logout: () => void;
}

const AUTH_STORAGE_KEY = "tracking-os-auth";
const AUTH_USER_STORAGE_KEY = "tracking-os-auth-user";
const AuthContext = createContext<AuthContextType | null>(null);

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
};

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    if (typeof window === "undefined") return false;
    return window.localStorage.getItem(AUTH_STORAGE_KEY) === "1";
  });
  const [adminEmail, setAdminEmail] = useState<string>(() => {
    if (typeof window === "undefined") return "";
    return window.localStorage.getItem(AUTH_USER_STORAGE_KEY) || "";
  });

  const login = (email: string, password: string) => {
    // Placeholder login: any non-empty credentials work.
    if (email.trim() && password.trim()) {
      setIsLoggedIn(true);
      setAdminEmail(email.trim());
      return true;
    }
    return false;
  };

  const logout = () => {
    setIsLoggedIn(false);
    setAdminEmail("");
  };

  useEffect(() => {
    if (typeof window === "undefined") return;
    if (isLoggedIn) {
      window.localStorage.setItem(AUTH_STORAGE_KEY, "1");
      return;
    }
    window.localStorage.removeItem(AUTH_STORAGE_KEY);
  }, [isLoggedIn]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    if (adminEmail) {
      window.localStorage.setItem(AUTH_USER_STORAGE_KEY, adminEmail);
      return;
    }
    window.localStorage.removeItem(AUTH_USER_STORAGE_KEY);
  }, [adminEmail]);

  return (
    <AuthContext.Provider value={{ isLoggedIn, adminEmail, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

