const parseUpdatedAt = (value: string): number => {
  const [datePartRaw, timePartRaw] = value.split(",");
  if (!datePartRaw || !timePartRaw) return 0;

  const dateParts = datePartRaw.trim().split(" ");
  if (dateParts.length < 3) return 0;

  const day = Number(dateParts[0]);
  const month = monthMap[dateParts[1].toLowerCase()];
  const year = Number(dateParts[2]);
  const [hourStr, minuteStr] = timePartRaw.trim().replace(/\s*WIB$/i, "").split(":");
  const hour = Number(hourStr);
  const minute = Number(minuteStr);

  if (
    Number.isNaN(day) ||
    month === undefined ||
    Number.isNaN(year) ||
    Number.isNaN(hour) ||
    Number.isNaN(minute)
  ) {
    return 0;
  }

  return new Date(year, month, day, hour, minute).getTime();
};

