  const [showAddDialog, setShowAddDialog] = useState(false);
  const [form, setForm] = useState<NewSubmissionInput>(emptyForm);
  const [formErrors, setFormErrors] = useState<Partial<NewSubmissionInput>>({});

  // Dialog konfirmasi hapus
  const [deleteTarget, setDeleteTarget] = useState<{ id: string; name: string } | null>(null);
  const [manageTarget, setManageTarget] = useState<{
    id: string;
    submissionNumber: string;
    organizationName: string;
  } | null>(null);
  const [isManageDialogOpen, setIsManageDialogOpen] = useState(false);
  const [shouldReturnToManageDialog, setShouldReturnToManageDialog] = useState(false);
  const [selectedStat, setSelectedStat] = useState<StatKey | null>(null);

  const submissionsByStat: Record<StatKey, typeof submissions> = {
    total: submissions,
    verifikasi: submissions.filter((s) => {
      const stages = deriveStages(s);
      return stages[1].status === "active";
    }),
    peninjauan: submissions.filter((s) => {
      const stages = deriveStages(s);
      return stages[2].status === "active";
    }),
    terbit: submissions.filter((s) => {
      const stages = deriveStages(s);
      return stages.every((st) => st.status === "completed");
    }),
  };

  const statCards = [
    { key: "total" as const, label: "Total Permohonan", value: submissionsByStat.total.length, icon: FileText, color: "text-accent" },
    { key: "verifikasi" as const, label: "Dalam Verifikasi Dokumen", value: submissionsByStat.verifikasi.length, icon: Search, color: "text-status-active" },
    { key: "peninjauan" as const, label: "Dalam Peninjauan", value: submissionsByStat.peninjauan.length, icon: Clock, color: "text-accent" },
    { key: "terbit" as const, label: "Izin Terbit", value: submissionsByStat.terbit.length, icon: CheckCircle2, color: "text-status-completed" },
  ];
  const selectedStatCard = selectedStat ? statCards.find((card) => card.key === selectedStat) : null;
  const selectedStatSubmissions = selectedStat ? submissionsByStat[selectedStat] : [];

  const filteredSubmissions = submissions.filter((s) => {
    if (!searchQuery.trim()) return true;
    const q = searchQuery.toLowerCase();
    return s.submissionNumber.toLowerCase().includes(q);
  });

  const sortedSubmissions = [...filteredSubmissions].sort((a, b) => {
    const statusPriority: Record<DisplayStatusType, number> = {
      revision: 0,
      active: 1,
      pending: 2,
      completed: 3,
    };
    const statusA = deriveDisplayStatus(a);
    const statusB = deriveDisplayStatus(b);

    switch (sortOption) {
      case "tahap":
        return (
          statusPriority[statusA.type] - statusPriority[statusB.type] ||
          parseUpdatedAt(b.lastUpdated) - parseUpdatedAt(a.lastUpdated)
        );
      case "latest":
        return parseUpdatedAt(b.lastUpdated) - parseUpdatedAt(a.lastUpdated);
      case "oldest":
        return parseUpdatedAt(a.lastUpdated) - parseUpdatedAt(b.lastUpdated);
      case "number":
        return a.submissionNumber.localeCompare(b.submissionNumber, "id-ID");
      case "name":
        return a.organizationName.localeCompare(b.organizationName, "id-ID");
      default:
        return 0;
    }
  });

  const totalPages = Math.ceil(sortedSubmissions.length / itemsPerPage);
  const paginatedSubmissions = sortedSubmissions.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handleOpenAdd = () => {
    setForm(emptyForm);
    setFormErrors({});
    setShowAddDialog(true);
  };

  const validateForm = (): boolean => {
    const errors: Partial<NewSubmissionInput> = {};
    if (!form.submissionNumber.trim()) errors.submissionNumber = "Wajib diisi";
    if (!form.organizationName.trim()) errors.organizationName = "Wajib diisi";
    if (!form.kbli.trim()) errors.kbli = "Wajib diisi";
    if (!form.pengajuanDate.trim()) errors.pengajuanDate = "Wajib diisi";
    if (form.pengajuanDate.trim() && Number.isNaN(new Date(form.pengajuanDate).getTime())) {
      errors.pengajuanDate = "Tanggal tidak valid";
    }

    // Cek duplikat nomor permohonan
    const duplicate = submissions.find(
      (s) => s.submissionNumber.toLowerCase() === form.submissionNumber.trim().toLowerCase()
    );
    if (duplicate) errors.submissionNumber = "Nomor permohonan sudah terdaftar";

    setFormErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleSubmitAdd = () => {
    if (!validateForm()) return;
    const dateObj = new Date(form.pengajuanDate);
    if (Number.isNaN(dateObj.getTime())) {
      setFormErrors((prev) => ({ ...prev, pengajuanDate: "Tanggal tidak valid" }));
      return;
    }
    const dateFormatted = dateObj.toLocaleDateString("id-ID", {
      day: "numeric", month: "long", year: "numeric",
    });
    addSubmission({
      ...form,
      submissionNumber: form.submissionNumber.trim(),
      organizationName: form.organizationName.trim(),
      kbli: form.kbli.trim(),
      pengajuanDate: dateFormatted,
    });
    setShowAddDialog(false);
    toast.success(`Permohonan ${form.submissionNumber.trim()} berhasil ditambahkan.`);
  };

  const handleConfirmDelete = () => {
    if (!deleteTarget) return;
    deleteSubmission(deleteTarget.id);
    toast.success(`Permohonan ${deleteTarget.name} berhasil dihapus.`);
    setShouldReturnToManageDialog(false);
    setIsManageDialogOpen(false);
    setManageTarget(null);
    setDeleteTarget(null);
  };

  const handleManageFromDialog = () => {
    if (!manageTarget) return;
    const targetId = manageTarget.id;
    setShouldReturnToManageDialog(false);
    setIsManageDialogOpen(false);
    setManageTarget(null);
    navigate(`/admin/kelola/${targetId}`);
  };

  const handleDeleteFromManage = () => {
    if (!manageTarget) return;
    setDeleteTarget({
      id: manageTarget.id,
      name: manageTarget.organizationName || manageTarget.submissionNumber,
    });
    setShouldReturnToManageDialog(true);
    setIsManageDialogOpen(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 relative overflow-hidden">
      {/* Decorative background blurs */}
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/5 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/3 pointer-events-none" />
      <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-blue-500/5 rounded-full blur-[100px] translate-y-1/2 -translate-x-1/3 pointer-events-none" />

      <AppHeader variant="admin" />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8 relative z-10">
        {/* Header Section */}
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h1 className="text-3xl font-heading font-black text-slate-800 tracking-tight">Dashboard Admin</h1>
            <p className="text-slate-500 font-medium mt-1">Kelola dan pantau seluruh permohonan izin PB UMKU terkini.</p>
          </div>
          <button
            onClick={handleOpenAdd}
            className="inline-flex items-center gap-2 px-5 py-2.5 bg-primary hover:bg-primary/95 text-white text-sm font-bold rounded-xl shadow-lg shadow-primary/25 hover:shadow-primary/40 hover:-translate-y-0.5 transition-all focus:outline-none focus:ring-2 focus:ring-primary/20"
          >
            <Plus className="w-5 h-5 stroke-[2.5]" />
            Buat Permohonan
          </button>
        </div>

        {/* Statistics Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6">
          {statCards.map((stat, i) => (
            <button
              key={stat.key}
              type="button"
              className="group bg-white border border-slate-200/80 shadow-[0_8px_30px_rgb(0,0,0,0.04)] rounded-[1.5rem] p-6 text-left hover:border-primary/20 hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] transition-all hover:-translate-y-1 focus:outline-none focus:ring-2 focus:ring-primary/20 relative overflow-hidden flex flex-col justify-between min-h-[140px]"
              onClick={() => setSelectedStat(stat.key)}
            >
              <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-slate-50 to-transparent rounded-bl-full pointer-events-none opacity-50 group-hover:from-primary/5 transition-colors" />

              <div className="flex items-center justify-between z-10">
                <p className="text-sm font-bold text-slate-500 line-clamp-2 pr-2 leading-tight">{stat.label}</p>
                <div className={`p-3 rounded-2xl bg-white shadow-sm ring-1 ring-slate-100/50 ${stat.color} group-hover:scale-110 group-hover:bg-slate-50 transition-all shrink-0`}>
                  <stat.icon className="w-5 h-5 stroke-[2.5]" />
                </div>
              </div>
              <div className="mt-4 z-10 flex items-baseline gap-2">
                <span className="text-4xl font-heading font-black tracking-tight text-slate-800">{stat.value}</span>
              </div>
            </button>
          ))}
        </div>

        {/* Application List Container */}
        <div className="bg-white border border-slate-200/80 shadow-[0_8px_30px_rgb(0,0,0,0.04)] rounded-[1.5rem] overflow-hidden relative z-10">
          <div className="p-6 sm:px-8 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-white/50">
            <div>
              <h2 className="text-xl font-heading font-black text-slate-800">Daftar Permohonan</h2>
              <p className="text-sm text-slate-500 font-medium">Cari, sortir, dan kelola seluruh pengajuan PB UMKU</p>
            </div>

            <div className="flex items-center gap-3 w-full sm:w-auto mt-2 sm:mt-0">
              {/* Search */}
              <div className="relative w-full sm:w-64 max-w-sm">
                <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none stroke-[2.5]" />
                <input
                  type="text"
                  placeholder="Cari Nomor..."
                  value={searchQuery}
                  onChange={(e) => {
                    setSearchQuery(e.target.value);
                    setCurrentPage(1);
                  }}
                  className="w-full pl-10 pr-9 py-2.5 text-[14px] font-medium rounded-xl border border-slate-200 bg-slate-50 text-slate-700 placeholder:text-slate-400 focus:bg-white focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/40 transition-all shadow-sm"
                />
                {searchQuery && (
                  <button
                    onClick={() => setSearchQuery("")}
                    className="absolute right-2.5 top-1/2 -translate-y-1/2 p-1 rounded-md hover:bg-slate-200/50 transition-colors text-slate-400 hover:text-slate-600"
                  >
                    <X className="w-3.5 h-3.5 stroke-[2.5]" />
                  </button>
                )}
              </div>

              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <button
                    type="button"
                    aria-label="Urutkan Daftar Permohonan"
                    className="p-2.5 bg-white border border-slate-200 shadow-sm rounded-xl hover:bg-slate-50 transition-colors focus:outline-none focus:ring-2 focus:ring-primary/20 shrink-0 text-slate-600 hover:text-slate-900"
                  >
                    <ArrowUpDown className="w-4 h-4 stroke-[2.5]" />
                  </button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-[180px] bg-white border border-slate-100 shadow-elevated rounded-xl z-50 p-1.5">
                  <DropdownMenuRadioGroup value={sortOption} onValueChange={(value) => setSortOption(value as SortOption)}>
                    <DropdownMenuRadioItem value="tahap" className="cursor-pointer py-2 pl-8 pr-4 text-sm hover:bg-slate-50 rounded-lg data-[state=checked]:bg-primary/10 data-[state=checked]:text-primary transition-colors font-semibold">Tahapan</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="latest" className="cursor-pointer py-2 pl-8 pr-4 text-sm hover:bg-slate-50 rounded-lg data-[state=checked]:bg-primary/10 data-[state=checked]:text-primary transition-colors font-semibold mt-1">Terbaru</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="oldest" className="cursor-pointer py-2 pl-8 pr-4 text-sm hover:bg-slate-50 rounded-lg data-[state=checked]:bg-primary/10 data-[state=checked]:text-primary transition-colors font-semibold mt-1">Terlama</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="number" className="cursor-pointer py-2 pl-8 pr-4 text-sm hover:bg-slate-50 rounded-lg data-[state=checked]:bg-primary/10 data-[state=checked]:text-primary transition-colors font-semibold mt-1">Nomor</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="name" className="cursor-pointer py-2 pl-8 pr-4 text-sm hover:bg-slate-50 rounded-lg data-[state=checked]:bg-primary/10 data-[state=checked]:text-primary transition-colors font-semibold mt-1">Nama Perusahaan/LPK</DropdownMenuRadioItem>
                  </DropdownMenuRadioGroup>
                </DropdownMenuContent>
              </DropdownMenu>

              {/* Tambah permohonan */}
              <button
                onClick={handleOpenAdd}
                title="Buat Permohonan Baru"
                aria-label="Buat Permohonan Baru"
                className="group p-2.5 bg-slate-900 text-white border border-slate-800 rounded-xl hover:bg-slate-800 transition-all shadow-md hover:shadow-lg focus:outline-none focus:ring-2 focus:ring-slate-900/30 shrink-0 flex items-center justify-center gap-2 px-4"
              >
                <Plus className="w-4 h-4 stroke-[3] group-hover:rotate-90 transition-transform" />
                <span className="text-sm font-bold hidden sm:inline-block">Buat</span>
              </button>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-slate-50/80 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider whitespace-nowrap">No. Permohonan</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider whitespace-nowrap">Nama Perusahaan / LPK</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider whitespace-nowrap">Tahapan Saat Ini</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider whitespace-nowrap">Terakhir Diperbarui</th>
                  <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider whitespace-nowrap text-center">Aksi</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {sortedSubmissions.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-16 text-center">
                      <div className="flex flex-col items-center justify-center text-slate-400">
                        <Search className="w-10 h-10 mb-4 text-slate-300" />
                        <p className="font-medium text-[15px] text-slate-500">Tidak ada permohonan yang ditemukan.</p>
                        <p className="text-sm mt-1">Coba gunakan kata kunci pencarian yang lain.</p>
                      </div>
                    </td>
                  </tr>
                ) : null}
                {paginatedSubmissions.map((s) => {
                  const display = deriveDisplayStatus(s);
                  const st = statusLabel[display.type];
                  return (
                    <tr key={s.id} className="hover:bg-slate-50/80 transition-colors group">
                      <td className="px-6 py-4 font-bold text-slate-700 whitespace-nowrap">{s.submissionNumber}</td>
                      <td className="px-6 py-4 text-slate-600 w-[300px]">
                        <div className="line-clamp-2 font-medium" title={s.organizationName}>{s.organizationName}</div>
                      </td>
                      <td className="px-6 py-4 text-[13px] font-bold whitespace-nowrap">
                        <span className={`inline-flex px-3 py-1.5 rounded-lg border border-transparent shadow-sm ${st.className.replace('whitespace-nowrap', '')} bg-opacity-10 opacity-90 group-hover:opacity-100`}>
                          {display.label}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-slate-500 text-[13px] font-medium whitespace-nowrap flex items-center gap-1.5 mt-0.5">
                        <Clock className="w-3.5 h-3.5 text-slate-400" />
                        {s.lastUpdated}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-center">
                        <button
                          onClick={() => {
                            setManageTarget({
                              id: s.id,
                              submissionNumber: s.submissionNumber,
                              organizationName: s.organizationName,
                            });
                            setIsManageDialogOpen(true);
                          }}
                          className="inline-flex items-center gap-1.5 px-4 py-2 text-xs font-bold bg-white text-slate-700 border border-slate-200 rounded-lg shadow-sm hover:bg-slate-50 hover:text-primary hover:border-primary/30 transition-all focus:outline-none focus:ring-2 focus:ring-primary/20"
                        >
                          <Pencil className="w-3.5 h-3.5" />
                          Kelola
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {
            totalPages > 1 && (
              <div className="p-4 border-t border-border/50 bg-white/40 flex items-center justify-between sm:justify-end gap-2">
                <button
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  className="px-4 py-2 text-sm font-semibold border border-border rounded-lg bg-white hover:bg-slate-50 disabled:opacity-50 transition-colors shadow-sm"
                >
                  Sebelumnya
                </button>
                <div className="text-sm font-medium px-4">
                  Halaman {currentPage} dari {totalPages}
                </div>
                <button
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                  className="px-4 py-2 text-sm font-semibold border border-border rounded-lg bg-white hover:bg-slate-50 disabled:opacity-50 transition-colors shadow-sm"
                >
                  Selanjutnya
                </button>
              </div>
            )}
        </div>
    </div>
    </main >

  {/* Modal Buat Permohonan Baru */ }
  < Dialog open = { showAddDialog } onOpenChange = { setShowAddDialog } >
    <DialogContent className="sm:max-w-md">
      <DialogHeader>
        <DialogTitle className="font-heading">Buat Permohonan Baru</DialogTitle>
      </DialogHeader>
      <div className="space-y-4 py-2">
        <div>
          <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">
            Tanggal Pengajuan <span className="text-status-revision">*</span>
          </label>
          <input
            type="date"
            max={new Date().toLocaleDateString('en-CA')}
            value={form.pengajuanDate}
            onChange={(e) => {
              setForm((f) => ({ ...f, pengajuanDate: e.target.value }));
              setFormErrors((err) => ({ ...err, pengajuanDate: undefined }));
            }}
            className={`w-full text-sm border rounded-lg px-3 py-2.5 bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-ring ${formErrors.pengajuanDate ? "border-status-revision" : "border-input"}`}
          />
          {formErrors.pengajuanDate && (
            <p className="text-xs text-status-revision mt-1">{formErrors.pengajuanDate}</p>
          )}
        </div>
        <div>
          <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">
            Nomor Permohonan <span className="text-status-revision">*</span>
          </label>
          <input
            type="text"
            value={form.submissionNumber}
            onChange={(e) => {
              setForm((f) => ({ ...f, submissionNumber: e.target.value }));
              setFormErrors((err) => ({ ...err, submissionNumber: undefined }));
            }}
            placeholder="Masukkan Nomor Permohonan"
            className={`w-full text-sm border rounded-lg px-3 py-2.5 bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring ${formErrors.submissionNumber ? "border-status-revision" : "border-input"}`}
          />
          {formErrors.submissionNumber && (
            <p className="text-xs text-status-revision mt-1">{formErrors.submissionNumber}</p>
          )}
        </div>
        <div>
          <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">
            Nama Perusahaan / LPK <span className="text-status-revision">*</span>
          </label>
          <input
            type="text"
            value={form.organizationName}
            onChange={(e) => {
              setForm((f) => ({ ...f, organizationName: e.target.value }));
              setFormErrors((err) => ({ ...err, organizationName: undefined }));
            }}
            placeholder="Masukkan Nama Perusahaan / LPK"
            className={`w-full text-sm border rounded-lg px-3 py-2.5 bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring ${formErrors.organizationName ? "border-status-revision" : "border-input"}`}
          />
          {formErrors.organizationName && (
            <p className="text-xs text-status-revision mt-1">{formErrors.organizationName}</p>
          )}
        </div>
        <div>
          <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-1.5">
            KBLI <span className="text-status-revision">*</span>
          </label>
          <input
            type="text"
            value={form.kbli}
            onChange={(e) => {
              setForm((f) => ({ ...f, kbli: e.target.value }));
              setFormErrors((err) => ({ ...err, kbli: undefined }));
            }}
            placeholder="Masukkan KBLI"
            className={`w-full text-sm border rounded-lg px-3 py-2.5 bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring ${formErrors.kbli ? "border-status-revision" : "border-input"}`}
          />
          {formErrors.kbli && (
            <p className="text-xs text-status-revision mt-1">{formErrors.kbli}</p>
          )}
        </div>
      </div>
      <DialogFooter className="gap-2">
        <button
          onClick={() => setShowAddDialog(false)}
          className="px-4 py-2 text-sm font-medium text-muted-foreground hover:bg-secondary rounded-lg transition-colors"
        >
          Batal
        </button>
        <button
          onClick={handleSubmitAdd}
          className="px-5 py-2 text-sm font-semibold bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors shadow-sm"
        >
          Buat Permohonan
        </button>
      </DialogFooter>
    </DialogContent>
  </Dialog >

  {/* Dialog Aksi Kelola */ }
  < Dialog
open = { isManageDialogOpen }
onOpenChange = {(open) => {
  setIsManageDialogOpen(open);
  if (!open && !deleteTarget) {
    setManageTarget(null);
    setShouldReturnToManageDialog(false);
  }
}}
  >
  <DialogContent className="sm:max-w-md">
    <DialogHeader>
      <DialogTitle className="font-heading">Kelola Permohonan</DialogTitle>
      <DialogDescription className="text-sm text-muted-foreground leading-relaxed">
        Pilih aksi untuk permohonan <span className="font-semibold text-foreground">{manageTarget?.submissionNumber}</span>.
      </DialogDescription>
    </DialogHeader>
    <div className="rounded-lg border border-border/70 bg-muted/20 px-3 py-2">
      <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-1">Nama Perusahaan/LPK</p>
      <p className="text-sm font-medium text-foreground line-clamp-2">{manageTarget?.organizationName || "-"}</p>
    </div>
    <DialogFooter className="gap-2 sm:justify-start">
      <button
        type="button"
        onClick={handleManageFromDialog}
        className="inline-flex items-center justify-center gap-2 px-4 py-2 text-sm font-semibold bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors"
      >
        <Pencil className="w-4 h-4" />
        Lanjutkan Proses
      </button>
      <button
        type="button"
        onClick={handleDeleteFromManage}
        className="inline-flex items-center justify-center gap-2 px-4 py-2 text-sm font-semibold bg-status-revision text-white rounded-lg hover:bg-status-revision/90 transition-colors"
      >
        <Trash2 className="w-4 h-4" />
        Hapus
      </button>
    </DialogFooter>
  </DialogContent>
  </Dialog >

  {/* Dialog Konfirmasi Hapus */ }
  < AlertDialog
open = {!!deleteTarget}
onOpenChange = {(open) => {
  if (open) return;
  setDeleteTarget(null);
  if (shouldReturnToManageDialog && manageTarget) {
    setIsManageDialogOpen(true);
  } else if (!isManageDialogOpen) {
    setManageTarget(null);
  }
  setShouldReturnToManageDialog(false);
}}
  >
  <AlertDialogContent>
    <AlertDialogHeader>
      <AlertDialogTitle className="font-heading">Hapus Permohonan?</AlertDialogTitle>
      <AlertDialogDescription>
        Tindakan ini akan menghapus permohonan <span className="font-semibold text-foreground">{deleteTarget?.name}</span> secara permanen dan tidak dapat dibatalkan.
      </AlertDialogDescription>
    </AlertDialogHeader>
    <AlertDialogFooter>
      <AlertDialogCancel>Batal</AlertDialogCancel>
      <AlertDialogAction
        onClick={handleConfirmDelete}
        className="bg-status-revision text-white hover:bg-status-revision/90"
      >
        Hapus
      </AlertDialogAction>
    </AlertDialogFooter>
  </AlertDialogContent>
  </AlertDialog >

  {/* Dialog Detail Statistik */ }
  < Dialog open = {!!selectedStat} onOpenChange = {(open) => { if (!open) setSelectedStat(null); }}>
    <DialogContent className="sm:max-w-3xl">
      <DialogHeader>
        <DialogTitle className="font-heading">
          {selectedStatCard?.label || "Detail Statistik"} ({selectedStatSubmissions.length})
        </DialogTitle>
      </DialogHeader>
      <div className="max-h-[60vh] overflow-y-auto pr-1">
        {selectedStatSubmissions.length === 0 ? (
          <p className="text-sm text-muted-foreground py-6 text-center">
            Tidak ada data pada kategori ini.
          </p>
        ) : (
          <div className="space-y-3">
            {selectedStatSubmissions.map((submission) => {
              const display = deriveDisplayStatus(submission);
              const status = statusLabel[display.type];

              return (
                <button
                  key={submission.id}
                  type="button"
                  onClick={() => {
                    setSelectedStat(null);
                    navigate(`/admin/kelola/${submission.id}`);
                  }}
                  className="w-full rounded-xl border border-border bg-background p-4 flex flex-col sm:flex-row sm:items-center gap-3 text-left transition-all duration-200 hover:bg-card hover:border-muted-foreground/30 hover:-translate-y-0.5 hover:shadow-md focus:outline-none"
                >
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-foreground truncate">{submission.submissionNumber}</p>
                    <p className="text-sm text-muted-foreground truncate">{submission.organizationName}</p>
                    <p className="text-xs text-muted-foreground mt-1">Terakhir diperbarui: {submission.lastUpdated}</p>
                  </div>
                  <div className="flex items-center gap-2 sm:gap-3">
                    <span className={`inline-flex items-center px-3 py-1 rounded-xl text-xs font-bold border border-black/5 ${status.className}`}>
                      {status.text}
                    </span>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </div>
      <DialogFooter>
        <button
          onClick={() => setSelectedStat(null)}
          className="px-4 py-2 text-sm font-medium text-muted-foreground hover:bg-secondary rounded-lg transition-colors"
        >
          Tutup
        </button>
      </DialogFooter>
    </DialogContent>
  </Dialog >
    </div >
  );
};

